#include <stdio.h>
#include <math.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    for(int tc=0; tc<T; ++tc){
        int n; while(scanf("%d", &n)!=1) ; // skip blank lines
        int type[105]; int left[105], right[105];
        for(int i=1;i<=n;++i){
            int x; scanf("%d", &x);
            if(x==0){ type[i]=0; }
            else{ type[i]=x; scanf("%d %d", &left[i], &right[i]); }
        }
        double low=0.0, high=1.0, mid;
        for(int it=0; it<60; ++it){
            mid=(low+high)/2.0;
            double prob[105];
            for(int i=1;i<=n;++i){
                if(type[i]==0) prob[i]=mid;
                else if(type[i]==1) prob[i]=prob[left[i]]+prob[right[i]]-prob[left[i]]*prob[right[i]]; // OR
                else prob[i]=prob[left[i]]*prob[right[i]]; // AND
            }
            if(prob[n] < 0.5) low=mid; else high=mid;
        }
        double ans=(low+high)/2.0;
        printf("%.5f\n", ans+1e-12); // tiny epsilon for correct rounding
    }
    return 0;
}

