import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int n = fs.nextInt();
            int[] type = new int[n + 1];
            int[] left = new int[n + 1];
            int[] right = new int[n + 1];
            for (int i = 1; i <= n; i++) {
                int x = fs.nextInt();
                if (x == 0) {
                    type[i] = 0;
                } else {
                    type[i] = x;
                    left[i] = fs.nextInt();
                    right[i] = fs.nextInt();
                }
            }
            double lo = 0.0, hi = 1.0;
            for (int it = 0; it < 60; it++) {
                double mid = (lo + hi) / 2.0;
                double[] prob = new double[n + 1];
                for (int i = 1; i <= n; i++) {
                    if (type[i] == 0) prob[i] = mid;
                    else if (type[i] == 1) prob[i] = prob[left[i]] + prob[right[i]] - prob[left[i]] * prob[right[i]]; // OR
                    else prob[i] = prob[left[i]] * prob[right[i]]; // AND
                }
                if (prob[n] < 0.5) lo = mid; else hi = mid;
            }
            double ans = (lo + hi) / 2.0;
            sb.append(String.format(java.util.Locale.US, "%.5f\n", ans + 1e-12));
        }
        System.out.print(sb.toString());
    }

    // Fast scanner handling blank lines
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is) { in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ' && c != -1);
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

